B.FR=new A.b4(B.bv,["Kabul Et","Reddet","S\xfcr\xfcm","Tebrikler!","SES AYARLARI","M\xfczik Efektleri","T\xfcm sesleri a\xe7 veya kapat","M\xfczik Seviyesi","Ses Efektleri","Efekt Seviyesi","D\u0130L","Dil Se\xe7imi","MEYDAN OKUMA","S\xfcre Limiti","Nas\u0131l Oynan\u0131r?","Tepsideki bloklar\u0131 s\xfcr\xfckleyip \u0131zgaraya b\u0131rak.","Bir sat\u0131r\u0131 veya s\xfctunu tamamen doldurursan temizlenir ve puan kazan\u0131rs\u0131n.","8 hamle ard arda yaparsan Kombo patlar ve 1 ipucu kazan\u0131rs\u0131n!","\u0130pu\xe7lar\u0131yla tepsiyi yenileyebilir, son hamleyi geri alabilir veya en dolu sat\u0131r\u0131 temizleyebilirsin.","Hi\xe7bir blok s\u0131\u011fmazsa ve ipucu kalmazsa oyun biter.","Oyun Bitti","Skor","En Y\xfcksek","Tekrar Oyna","Ana Men\xfc","Yetersiz!","Tamam","Ba\u015fla","Block Blast","Bulmaca","Zaten Al\u0131nd\u0131!","Bug\xfcnk\xfc \xf6d\xfcl\xfcn\xfc zaten ald\u0131n.\nYar\u0131n tekrar gel!","G\xfcnl\xfck \xd6d\xfcl!","+10 \u0130pucu kazand\u0131n!\nYar\u0131n tekrar gel.","Alttaki tepside bloklar var.\nBir blo\u011fu bas\u0131l\u0131 tut ve \u0131zgaraya s\xfcr\xfckle!","Bir sat\u0131r\u0131 veya s\xfctunu tamamen doldurursan temizlenir ve puan kazan\u0131rs\u0131n!","Bunlar g\xfc\xe7lendirme butonlar\u0131.\nTepsiyi yenile, geri al veya en dolu sat\u0131r\u0131 temizle!","Buras\u0131 senin skorun.\n8 ard\u0131\u015f\u0131k hamlede Combo yapar, ekstra ipucu kazan\u0131rs\u0131n!","\u0130leri","Atla","Anlad\u0131m!","T\xdcM\xdcN\xdc\nPATLAT!","BLO\u011eU\n\xc7EK!","\u015eEK\u0130LLER\u0130\nDE\u011e\u0130\u015eT\u0130R!","Premium'a Ge\xe7","Reklams\u0131z Deneyim","T\xfcm Kelimelere Eri\u015fin","S\u0131n\u0131rs\u0131z Oyun Hakk\u0131","S\u0131n\u0131rs\u0131z \u0130pucu","Sat\u0131n Al","Premium \u015fu anda kullan\u0131lam\u0131yor.","Sat\u0131n Al\u0131mlar\u0131 Geri Y\xfckle","Premium","T\xfcm \xf6zellikler aktif"],t.l)
B.FU=new A.b4(B.bv,["Akzeptieren","Ablehnen","Version","Gl\xfcckwunsch!","TONEINSTELLUNGEN","Musik & Soundeffekte","Alle T\xf6ne ein- oder ausschalten","Musiklautst\xe4rke","Soundeffekte","Effektlautst\xe4rke","SPRACHE","Sprachauswahl","HERAUSFORDERUNG","Zeitlimit","Wie spielt man?","Ziehe Bl\xf6cke aus dem Tablett und lege sie im Raster ab.","Wenn du eine Reihe oder Spalte vollst\xe4ndig f\xfcllst, wird sie gel\xf6scht und du erh\xe4ltst Punkte.","Mache 8 Z\xfcge hintereinander, um ein Kombo auszul\xf6sen und 1 Hinweis zu erhalten!","Nutze Hinweise, um das Tablett zu erneuern, den letzten Zug r\xfcckg\xe4ngig zu machen oder die vollste Reihe zu l\xf6schen.","Wenn kein Block passt und keine Hinweise \xfcbrig sind, ist das Spiel vorbei.","Spielende","Punkte","Beste","Nochmal spielen","Hauptmen\xfc","Nicht genug!","OK","Start","Block Blast","Kreuzwortr\xe4tsel","Bereits gefordert!","Du hast die heutige Belohnung bereits gesammelt.\nKomm morgen zur\xfcck!","T\xe4gliche Belohnung!","+10 Hinweise verdient!\nBis morgen.","Es gibt Bl\xf6cke im Tablett unten.\nHalte einen Block gedr\xfcckt und ziehe ihn auf das Gitter!","Wenn du eine Reihe oder Spalte vollst\xe4ndig ausf\xfcllst, wird sie gel\xf6scht \u2013 du verdienst Punkte!","Dies sind Power-up-Tasten.\nTablett erneuern, einen Zug r\xfcckg\xe4ngig machen oder die vollste Reihe l\xf6schen!","Dies ist dein Punktestand.\nMache 8 Z\xfcge hintereinander, um ein Combo auszul\xf6sen und Bonushinweise zu verdienen!","Weiter","\xdcberspringen","Verstanden!","ALLES\nSPRENGEN!","BLOCK\nZIEHEN!","FORMEN\n\xc4NDERN!","Premium freischalten","Werbefreies Erlebnis","Zugriff auf alle W\xf6rter","Unbegrenzte Spiele","Unbegrenzte Hinweise","Kaufen","Premium ist derzeit nicht verf\xfcgbar.","K\xe4ufe wiederherstellen","Premium","Alle Funktionen freigeschaltet"],t.l)
B.FV=new A.b4(B.bv,["Accepter","Refuser","Version","F\xe9licitations!","PARAM\xc8TRES SONORES","Musique et Effets Sonores","Activer ou d\xe9sactiver tous les sons","Volume de la Musique","Effets Sonores","Volume des Effets","LANGUE","S\xe9lection de la langue","D\xc9FI","Limite de temps","Comment jouer?","Faites glisser les blocs du plateau et d\xe9posez-les sur la grille.","Lorsque vous remplissez compl\xe8tement une ligne ou une colonne, elle s'efface et vous gagnez des points.","Faites 8 coups d'affil\xe9e pour d\xe9clencher un Combo et gagner 1 indice!","Utilisez les indices pour actualiser le plateau, annuler le dernier coup ou effacer la ligne la plus pleine.","Si aucun bloc ne rentre et qu'il vous reste aucun indice, le jeu se termine.","Jeu Termin\xe9","Score","Meilleur","Rejouer","Menu Principal","Pas Assez!","OK","Commencer","Block Blast","Mots Crois\xe9s","D\xe9j\xe0 R\xe9clam\xe9!","Vous avez d\xe9j\xe0 collect\xe9 la r\xe9compense d'aujourd'hui.\nRevenz demain!","R\xe9compense Quotidienne!","Vous avez gagn\xe9 +10 indices!\n\xc0 bient\xf4t.","Il y a des blocs dans le plateau ci-dessous.\nAppuyez et maintenez un bloc, puis faites-le glisser sur la grille!","Remplissez compl\xe8tement une ligne ou une colonne et elle s'efface \u2013 gagnant vous des points!","Ce sont des boutons d'am\xe9lioration.\nActualisez le plateau, annulez un coup ou effacez la ligne la plus pleine!","C'est votre score.\nFaites 8 coups d'affil\xe9e pour d\xe9clencher un Combo et gagner des indices bonus!","Suivant","Ignorer","Compris!","TOUT\nEXPLOSER!","TIRER\nBLOC!","CHANGER\nFORMES!","Passer \xe0 Premium","Exp\xe9rience sans Publicit\xe9","Acc\xe8s \xe0 Tous les Mots","Parties Illimit\xe9es","Indices Illimit\xe9s","Acheter","Premium est actuellement indisponible.","Restaurer les Achats","Premium","Toutes les fonctionnalit\xe9s activ\xe9es"],t.l)
B.FP=new A.b4(B.bv,["Aceptar","Rechazar","Versi\xf3n","\xa1Felicitaciones!","CONFIGURACI\xd3N DE SONIDO","M\xfasica y Efectos de Sonido","Activar o desactivar todos los sonidos","Volumen de la M\xfasica","Efectos de Sonido","Volumen de Efectos","IDIOMA","Selecci\xf3n de Idioma","DESAF\xcdO","L\xedmite de Tiempo","\xbfC\xf3mo jugar?","Arrastra bloques de la bandeja y su\xe9ltalos en la cuadr\xedcula.","Cuando llenas completamente una fila o columna, se borra y ganas puntos.","\xa1Haz 8 movimientos seguidos para activar un Combo y ganar 1 pista!","Usa pistas para actualizar la bandeja, deshacer el \xfaltimo movimiento o borrar la fila m\xe1s llena.","Si ning\xfan bloque encaja y no te quedan pistas, el juego termina.","Fin del Juego","Puntuaci\xf3n","Mejor","Jugar de Nuevo","Men\xfa Principal","\xa1No Hay Suficientes!","OK","Comenzar","Block Blast","Crucigramas","\xa1Ya Reclamado!","Ya recopilaste la recompensa de hoy.\n\xa1Vuelve ma\xf1ana!","\xa1Recompensa Diaria!","\xa1Ganaste +10 pistas!\nHasta ma\xf1ana.","Hay bloques en la bandeja debajo.\n\xa1Presiona y mant\xe9n un bloque, luego arr\xe1stralo a la cuadr\xedcula!","Llena completamente una fila o columna y se borra - \xa1ganando puntos!","Estos son botones de potenciaci\xf3n.\n\xa1Actualiza la bandeja, deshace un movimiento o borra la fila m\xe1s llena!","Esta es tu puntuaci\xf3n.\n\xa1Haz 8 movimientos seguidos para activar un Combo y ganar pistas bonus!","Siguiente","Saltar","\xa1Entendido!","\xa1EXPLOTAR\nTODO!","\xa1TIRAR\nBLOQUE!","\xa1CAMBIAR\nFORMAS!","Pasar a Premium","Experiencia Sin Anuncios","Acceso a Todas las Palabras","Partidas Ilimitadas","Pistas Ilimitadas","Comprar","Premium no est\xe1 disponible actualmente.","Restaurar Compras","Premium","Todas las funciones activadas"],t.l)
B.FS=new A.b4(B.bv,["Accetta","Rifiuta","Versione","Congratulazioni!","IMPOSTAZIONI AUDIO","Musica ed Effetti Sonori","Attiva o disattiva tutti i suoni","Volume della Musica","Effetti Sonori","Volume Effetti","LINGUA","Selezione della Lingua","SFIDA","Limite di Tempo","Come Giocare?","Trascinare i blocchi dal vassoio e rilasciarli sulla griglia.","Quando riempi completamente una riga o una colonna, si cancella e guadagni punti.","Fai 8 mosse consecutive per attivare un Combo e guadagna 1 suggerimento!","Usa i suggerimenti per aggiornare il vassoio, annullare l'ultima mossa o cancellare la riga pi\xf9 piena.","Se nessun blocco si adatta e non ti rimangono suggerimenti, il gioco termina.","Fine della Partita","Punteggio","Migliore","Gioca di Nuovo","Menu Principale","Non Abbastanza!","OK","Inizia","Block Blast","Cruciverba","Gi\xe0 Rivendicato!","Hai gi\xe0 raccolto la ricompensa di oggi.\nTorna domani!","Ricompensa Giornaliera!","Hai guadagnato +10 suggerimenti!\nA domani.","Ci sono blocchi nel vassoio sottostante.\nPremi e tieni premuto un blocco, quindi trascinalo sulla griglia!","Riempi completamente una riga o una colonna e si cancella - guadagnando punti!","Questi sono pulsanti di potenziamento.\nAggiorna il vassoio, annulla una mossa o cancella la riga pi\xf9 piena!","Questo \xe8 il tuo punteggio.\nFai 8 mosse consecutive per attivare un Combo e guadagna suggerimenti bonus!","Avanti","Salta","Ho capito!","ESPLODI\nTUTTO!","TIRA\nBLOCCO!","CAMBIA\nFORME!","Passa a Premium","Esperienza Senza Pubblicit\xe0","Accesso a Tutte le Parole","Partite Illimitate","Suggerimenti Illimitati","Acquista","Premium non \xe8 al momento disponibile.","Ripristina Acquisti","Premium","Tutte le funzionalit\xe0 attive"],t.l)
B.FT=new A.b4(B.bv,["Aceitar","Recusar","Vers\xe3o","Parab\xe9ns!","CONFIGURA\xc7\xd5ES DE SOM","M\xfasica e Efeitos Sonoros","Ativar ou desativar todos os sons","Volume da M\xfasica","Efeitos Sonoros","Volume dos Efeitos","IDIOMA","Sele\xe7\xe3o de Idioma","DESAFIO","Limite de Tempo","Como Jogar?","Arraste blocos da bandeja e solte-os na grade.","Quando voc\xea preenche completamente uma linha ou coluna, ela se limpa e voc\xea ganha pontos.","Fa\xe7a 8 movimentos seguidos para acionar um Combo e ganhe 1 dica!","Use dicas para atualizar a bandeja, desfazer o \xfaltimo movimento ou limpar a linha mais cheia.","Se nenhum bloco se encaixar e voc\xea n\xe3o tiver dicas, o jogo termina.","Fim do Jogo","Pontua\xe7\xe3o","Melhor","Jogar Novamente","Menu Principal","N\xe3o H\xe1 Suficientes!","OK","Come\xe7ar","Block Blast","Palavras Cruzadas","J\xe1 Reivindicado!","Voc\xea j\xe1 coletou a recompensa de hoje.\nVolte amanh\xe3!","Recompensa Di\xe1ria!","Voc\xea ganhou +10 dicas!\nAt\xe9 amanh\xe3.","H\xe1 blocos na bandeja abaixo.\nPressione e mantenha um bloco, depois arraste-o para a grade!","Preencha completamente uma linha ou coluna e ela se limpa - ganhando pontos!","Estes s\xe3o bot\xf5es de pot\xeancia.\nAtualize a bandeja, desfa\xe7a um movimento ou limpe a linha mais cheia!","Esta \xe9 sua pontua\xe7\xe3o.\nFa\xe7a 8 movimentos seguidos para acionar um Combo e ganhe dicas de b\xf4nus!","Pr\xf3ximo","Pular","Entendi!","EXPLODIR\nTUDO!","PUXAR\nBLOCO!","MUDAR\nFORMAS!","Tornar-se Premium","Experi\xeancia Sem An\xfancios","Acesso a Todas as Palavras","Jogos Ilimitados","Dicas Ilimitadas","Comprar","O Premium n\xe3o est\xe1 dispon\xedvel no momento.","Restaurar Compras","Premium","Todos os recursos ativados"],t.l)
